-- Migration for paper_plans table (All GATE Papers)
CREATE TABLE IF NOT EXISTS public.paper_plans (
  id bigint GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
  paper text NOT NULL,
  code text NOT NULL UNIQUE,
  category text NOT NULL,
  target_year text NOT NULL DEFAULT 'GATE 2025/2026',
  priority text NOT NULL DEFAULT 'Reference',
  notes text,
  syllabus_pdf text NOT NULL DEFAULT '#',
  youtube text NOT NULL DEFAULT '#',
  pdf_resources text NOT NULL DEFAULT '#',
  created_at timestamp with time zone DEFAULT now()
);

-- Enable RLS
ALTER TABLE public.paper_plans ENABLE ROW LEVEL SECURITY;

-- Allow public read access
CREATE POLICY "Public paper_plans read access" ON public.paper_plans
  FOR SELECT USING (true);

-- Insert GATE papers seed data
ON CONFLICT (code) DO NOTHING;
